import { Link } from '@chakra-ui/react';
import { ActionPageTableRow, ActionPageType, IActionPage } from '@domain/actionPages';
import { useGetAccount } from '@state/accounts';
import { useGetAllCustomDomains } from '@state/customDomains';
import { useFeatureFlag } from '@state/featureFlags';
import { usePermissions } from '@state/utils';
import { ActionMenu } from '@ui/components/ActionMenu';
import { TagList } from '@ui/components/atoms/Tag';
import { ClipboardButton } from '@ui/components/Button';
import { ActionPageTagsPopover } from '@ui/components/Popover';
import { CellContentWithAction, StatusTag } from '@ui/components/Table';
