import { useTranslation } from 'react-i18next';
import { Column, Row } from 'react-table';

type Props = {
  getViewHref: (row: IActionPage) => string;
  onActivate: (id: string) => void;
  onArchive: (id: string) => void;
  onClone: (id: string, pageType: ActionPageType) => void;
  onManageTags: () => void;
  onOpenPauseModal: () => void;
  pageIndex: number;
  pageSize: number;
  setSelectedRows: (rows: Row<IActionPage>[] | undefined, all: boolean) => void;
};

export const useActionPagesColumns = ({
  getViewHref,
  onActivate,
  onArchive,
  onClone,
  onManageTags,
  onOpenPauseModal,
  pageIndex,
  pageSize,
  setSelectedRows,
}: Props) => {
  const { t } = useTranslation('actionPages');
  const { t: tCommon } = useTranslation('common');
  const { currentAccount } = useGetAccount();
  const { customDomains } = useGetAllCustomDomains({});
  const enableTagging = useFeatureFlag('actionPages.tagging');
  const { accountsWrite, actionPagesRead, actionPagesWrite, billingAgreementsRead } =
    usePermissions();

  const numberColumn = useMemo<Column<ActionPageTableRow>>(
    () => ({
      accessor: 'number',
      Cell: ({ row }) => (
        <Label variant="regular">
          {(pageSize * (pageIndex - 1) + row.index + 1).toLocaleString()}
        </Label>
      ),
      disableGroupBy: true,
      disableResizing: true,
      Header: '#',
      maxWidth: 50,
      minWidth: 50,
      width: 50,
    }),
    [pageIndex, pageSize]
  );

  const nameColumn = useMemo<Column<ActionPageTableRow>>(
    () => ({
      accessor: 'name',
      Cell: ({ row, value }) => {
        const isActive = row.original.status === 'active';
        const isArchived = row.original.status === 'archived';

        return (
          <CellContentWithAction>
            {value}
            {currentAccount ? (
              <ActionMenu
                actions={[
                  {
                    href: getViewHref(row.original),
                    isDisabled: !actionPagesRead,
                    isExternal: true,
                    label: tCommon('button.view'),
                  },
                  {
                    href: isEventPage(row.original.pageType)
                      ? `/accounts/${currentAccount.id}/builder/${row.original.id}`
                      : `/accounts/${currentAccount.id}/action_pages/${row.original.id}/edit`,
                    isDisabled: !actionPagesWrite,
                    label: t('button.edit'),
                  },
                  {
                    isDisabled: !actionPagesWrite || !billingAgreementsRead,
                    label: t('button.clone'),
                    onClick: () => onClone(row.original.id, row.original.pageType),
                  },
                  ...(isEventPage(row.original.pageType)
                    ? []
                    : [
                        {
                          href: `/accounts/${currentAccount?.id}/submissions?actionPageId=${row.original.id}`,
                          isDisabled: !actionPagesRead,
                          label: t('button.viewSubmissions'),
                        },
                      ]),
                  {
                    isDisabled: !actionPagesWrite,
                    label: `${isActive ? t('button.pause') : t('button.unpause')}`,
                    onClick: isActive
                      ? () => {
                          setSelectedRows([row], false);
                          onOpenPauseModal();
                        }
                      : () => onActivate(row.original.id),
                  },
                  ...(!isActive && !isArchived
                    ? [
                        {
                          isDisabled: !actionPagesWrite,
                          label: t('button.archive'),
                          onClick: () => onArchive(row.original.id),
                        },
                      ]
                    : []),
                ]}
              />
            ) : null}
          </CellContentWithAction>
        );
      },
      Header: t('headers.name'),
      minWidth: 200,
      rowHeader: true,
      sticky: true,
    }),
    [
      actionPagesRead,
      actionPagesWrite,
      billingAgreementsRead,
      currentAccount,
      getViewHref,
      onActivate,
      onArchive,
      onClone,
      onOpenPauseModal,
      setSelectedRows,
      t,
      tCommon,
    ]
  );

  const statusColumn = useMemo<Column<ActionPageTableRow>>(
    () => ({
      accessor: 'status',
      Cell: ({ row }) => <StatusTag status={row.original.status || 'active'} />,
      Header: t('headers.status'),
    }),
    [t]
  );

  const tagsColumn = useMemo<Column<ActionPageTableRow> | undefined>(
    () =>
      enableTagging
        ? {
            accessor: 'accessTags',
            Cell: ({ row }) => (
              <CellContentWithAction isStatic>
                <TagList
                  getTagProps={(tag) => ({ backgroundColor: tag.color })}
                  tags={row.original.accessTags || []}
                />
                <ActionPageTagsPopover
                  actionPage={row.original}
                  filter={(tag) => accountsWrite || !tag.default}
                  onManageTags={onManageTags}
                />
              </CellContentWithAction>
            ),
            Header: t('headers.tags'),
            minWidth: 60,
          }
        : undefined,
    [accountsWrite, enableTagging, onManageTags, t]
  );

  const pageColumn = useMemo<Column<ActionPageTableRow>>(
    () => ({
      accessor: 'pageType',
      Cell: ({ row }) => <Text casing="capitalize">{row.original.pageType}</Text>,
      Header: t('headers.pageType'),
    }),
    [t]
  );

  const slugColumn = useMemo<Column<ActionPageTableRow>>(
    () => ({
      accessor: 'slug',

