        nameColumn,
        statusColumn,
        tagsColumn,
        pageColumn,
        slugColumn,
        idColumn,
        submissionsColumn,
      ].filter(isDefined),
    [
      numberColumn,
      nameColumn,
      statusColumn,
      tagsColumn,
      pageColumn,
      slugColumn,
      idColumn,
      submissionsColumn,
    ]
  );
};

